// NQxb_Messaging__Build_Dispatch_Response
// Build internal dispatch response per contract 721cfe50
// Extract provider_metadata from Google Calendar response per c074f0e1
// v2.0: Added recurrence to request_echo (T124)

const calResponse = $json;
const request = $node['NQxb_Messaging__Normalize_Request'].json;

// Check if Calendar returned an error
if (calResponse.error || calResponse.statusCode >= 400) {
  const errorMsg = calResponse.error?.message
    ?? calResponse.message
    ?? JSON.stringify(calResponse).substring(0, 500);

  return [{ json: {
    dispatch_ok: false,
    gw_action: 'messaging.create_calendar_event',
    provider: 'google_calendar',
    error_code: 'PROVIDER_DISPATCH_FAILED',
    error_message: `Google Calendar API error: ${errorMsg}`.substring(0, 500),
    timestamp: new Date().toISOString(),
    trace_id: request.trace_id,
    _request: request,
  }}];
}

// Success — extract provider metadata per c074f0e1
const event_id = calResponse.id ?? null;
const html_link = calResponse.htmlLink ?? null;

return [{ json: {
  dispatch_ok: true,
  gw_action: 'messaging.create_calendar_event',
  provider: 'google_calendar',
  timestamp: new Date().toISOString(),
  trace_id: request.trace_id,
  provider_metadata: {
    event_id: event_id,
    html_link: html_link,
  },
  request_echo: {
    title: request.title,
    start: request.start,
    end: request.end,
    recurrence: request.recurrence ?? null,
  },
  _request: request,
}}];

// NQxb_Messaging__Route_Dispatch
// Route based on dispatch_ok: true → save artifact, false → error
// v1.0

const dispatch = $json;

if (dispatch.dispatch_ok === true) {
  return [{ json: dispatch }];
}

// Dispatch failed — will be routed to error shaper via separate connection
return [];

// NQxb_Messaging__Check_Save
// Verify both spine and extension saves succeeded
// v1.0

const spineResult = $node['NQxb_Messaging__Save_Spine'].json;
const extResult = $json;
const dispatch = $node['NQxb_Messaging__Build_Dispatch_Response'].json;

const spineData = Array.isArray(spineResult) ? spineResult[0] : spineResult;
const artifact_id = spineData?.artifact_id ?? null;

if (!artifact_id) {
  return [{ json: {
    save_ok: false,
    dispatch: dispatch,
  }}];
}

const extData = Array.isArray(extResult) ? extResult[0] : extResult;
if (extData?.error || extData?.statusCode >= 400) {
  return [{ json: {
    save_ok: false,
    dispatch: dispatch,
    artifact_id: artifact_id,
  }}];
}

return [{ json: {
  save_ok: true,
  artifact_id: artifact_id,
  dispatch: dispatch,
}}];

// NQxb_Messaging__Shape_Success
// Build Gateway success envelope per contract 963731f3
// v1.0

const data = $json;
const dispatch = data.dispatch;

return [{ json: {
  ok: true,
  gw_action: 'messaging.create_calendar_event',
  artifact_id: data.artifact_id,
  timestamp: new Date().toISOString(),
  trace_id: dispatch.trace_id,
  provider_metadata: dispatch.provider_metadata,
}}];

// NQxb_Messaging__Shape_Error
// Build Gateway error envelope
// Handles: VALIDATION_ERROR, PROVIDER_DISPATCH_FAILED, ARTIFACT_SAVE_FAILED
// v1.0

const data = $json;

// Path 1: Validation error (from Check_Validation false branch)
if (data.error_code === 'VALIDATION_ERROR') {
  return [{ json: {
    ok: false,
    _gw_route: 'error',
    error: {
      code: 'VALIDATION_ERROR',
      message: data.error_message,
      details: {
        gw_action: 'messaging.create_calendar_event',
        field: data.error_field ?? null,
        rule: data.error_message,
        trace_id: data.trace_id,
      },
    },
  }}];
}

// Path 2: Provider dispatch failed (dispatch_ok=false)
if (data.dispatch_ok === false) {
  return [{ json: {
    ok: false,
    _gw_route: 'error',
    error: {
      code: 'PROVIDER_DISPATCH_FAILED',
      message: data.error_message,
      details: {
        gw_action: 'messaging.create_calendar_event',
        provider: 'google_calendar',
        provider_status: data.provider_status ?? null,
        provider_message: (data.error_message ?? '').substring(0, 500),
        trace_id: data.trace_id,
      },
    },
  }}];
}

// Path 3: Artifact save failed (save_ok=false)
if (data.save_ok === false) {
  const dispatch = data.dispatch ?? {};
  return [{ json: {
    ok: false,
    _gw_route: 'error',
    error: {
      code: 'ARTIFACT_SAVE_FAILED',
      message: 'Calendar event created successfully but artifact record failed to save',
      details: {
        gw_action: 'messaging.create_calendar_event',
        dispatch_succeeded: true,
        provider_metadata: dispatch.provider_metadata ?? null,
        trace_id: dispatch.trace_id ?? null,
      },
    },
  }}];
}

// Fallback
return [{ json: {
  ok: false,
  _gw_route: 'error',
  error: {
    code: 'UNKNOWN_ERROR',
    message: 'Unexpected error in calendar event workflow',
    details: data,
  },
}}];
